#include <bits/stdc++.h>
using namespace std;
const int N=4e3+3;
int n,m,k,t,val[N][N],f[N][N],q[N],ans;
int main(){
    scanf("%d%d%d%d",&n,&m,&k,&t);
    while(k--){
        int a,b,c;
        scanf("%d%d%d",&a,&b,&c);
        val[a][b]=c;
    }
    for(int i=1;i<=n;i++){
        int l=1,r=0;
        for(int j=1;j<=min(m,t);j++){
            while(l<=r && f[i-1][q[r]]<=f[i-1][j])
                r--;
            q[++r]=j;
        }
        for(int j=1;j<=m;j++){
            while(l<=r && q[l]<j-t)
                l++;
            if(j+t<=m)
                while(l<=r && f[i-1][q[r]]<=f[i-1][j+t])
                    r--;
            q[++r]=j+t;
            f[i][j]=f[i-1][q[l]]+val[i][j];
        }
    }
    for(int j=1;j<=m;j++)
        ans=max(ans,f[n][j]);
    printf("%d",ans);
    return 0;
}
